229→/**
230→ * Updates or inserts a new whitespace element with [text] before the given node. If the node itself is a whitespace
231→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
232→ * added after the previous leaf node.
233→ */
234→public fun ASTNode.upsertWhitespaceBeforeMe(text: String) {
235→    if (this is LeafElement) {
236→        if (this.elementType == WHITE_SPACE) {
237→            return replaceWhitespaceWith(text)
238→        }
239→        val previous = treePrev ?: prevLeaf()
240→        if (previous != null && previous.elementType == WHITE_SPACE) {
241→            previous.replaceWhitespaceWith(text)
242→        } else {
243→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
244→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
245→            }
246→        }
247→    } else {
248→        val prevLeaf =
249→            requireNotNull(prevLeaf()) {
250→                "Can not upsert a whitespace if the first node is a non-leaf node"
251→            }
252→        prevLeaf.upsertWhitespaceAfterMe(text)
253→    }
254→}
255→
256→private fun ASTNode.replaceWhitespaceWith(text: String) {
257→    require(this.elementType == WHITE_SPACE)
258→    if (this.text != text) {
259→        (this.psi as LeafElement).rawReplaceWithText(text)
260→    }
261→}
262→
263→/**
264→ * Updates or inserts a new whitespace element with [text] after the given node. If the node itself is a whitespace
265→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
266→ * added after the last child leaf.
267→ */
268→public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
269→    if (this is LeafElement) {
270→        if (this.elementType == WHITE_SPACE) {
271→            return replaceWhitespaceWith(text)
272→        }
273→        val next = treeNext ?: nextLeaf()
274→        if (next != null && next.elementType == WHITE_SPACE) {
275→            next.replaceWhitespaceWith(text)
276→        } else {
277→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
278→                (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
279→            }
280→        }
281→    } else {
282→        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
283→    }
284→}
