306→public fun ASTNode.lineIndent(): String {
307→    var leaf = this.prevLeaf()
308→    while (leaf != null) {
309→        if (leaf.elementType == WHITE_SPACE && leaf.textContains('\n')) {
310→            return leaf.text.substring(leaf.text.lastIndexOf('\n') + 1)
311→        }
312→        leaf = leaf.prevLeaf()
313→    }
314→    return ""
