317→/**
318→ * Get the current indentation of the line containing the [ASTNode]. By default, this indentation starts with a newline (\n) character.
319→ */
320→public fun ASTNode.indent(includeNewline: Boolean = true): String =
321→    leaves(forward = false)
322→        .firstOrNull { it.isWhiteSpaceWithNewline() }
323→        ?.text
324→        ?.substringAfterLast('\n')
325→        .orEmpty() // Fallback if node is not preceded by any newline character
326→        .applyIf(includeNewline) { prefixIfNot("\n") }
