328→/**
329→ *  Print content of a node and the element type of the node, its parent and its direct children. Utility is meant to
330→ *  be used during development only. Please do not remove.
331→ */
332→@Suppress("unused")
333→public fun ASTNode.logStructure(): ASTNode =
334→    also {
335→        println("Processing ${text.replaceTabAndNewline()} : Type $elementType with parent ${treeParent?.elementType} ")
336→        children()
337→            .toList()
338→            .map {
339→                println("  ${it.text.replaceTabAndNewline()} : Type ${it.elementType}")
340→            }
341→    }
