 38→    private var rootNode: ASTNode? = null
 39→    private var foundByKeyword = false
 40→
 41→    override fun beforeVisitChildNodes(
 42→        node: ASTNode,
 43→        autoCorrect: Boolean,
 44→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 45→    ) {
 46→        if (node.isRoot()) {
 47→            rootNode = node
 48→        }
 49→        when (node.elementType) {
 50→            PACKAGE_DIRECTIVE -> {
 51→                val packageDirective = node.psi as KtPackageDirective
 52→                packageName = packageDirective.qualifiedName
 53→            }
 54→            IMPORT_DIRECTIVE -> {
 55→                val importPath = (node.psi as KtImportDirective).importPath!!
 56→                if (imports.containsKey(importPath)) {
 57→                    // Emit directly when same import occurs more than once
 58→                    emit(node.startOffset, "Unused import", true)
 59→                    if (autoCorrect) {
 60→                        node.psi.delete()
 61→                    }
 62→                } else {
 63→                    imports[importPath] = node
 64→                }
 65→            }
 66→            DOT_QUALIFIED_EXPRESSION -> {
 67→                if (node.isExpressionForStaticImportWithExistingParentImport()) {
 68→                    parentExpressions.add(node.text.substringBeforeLast("("))
 69→                }
 70→            }
 71→            MARKDOWN_LINK -> {
 72→                node
 73→                    .psi
 74→                    .safeAs<KDocLink>()
 75→                    ?.let { kdocLink ->
 76→                        val linkText = kdocLink.getLinkText().removeBackticksAndTrim()
 77→                        ref.add(Reference(linkText.split('.').first(), false))
 78→                        ref.add(Reference(linkText.split('.').last(), false))
 79→                    }
 80→            }
 81→            REFERENCE_EXPRESSION, OPERATION_REFERENCE -> {
 82→                if (!node.isPartOf(IMPORT_DIRECTIVE)) {
 83→                    val identifier = if (node is CompositeElement) {
 84→                        node.findChildByType(IDENTIFIER)
 85→                    } else {
 86→                        node
 87→                    }
 88→                    identifier
 89→                        ?.let { identifier.text }
 90→                        ?.takeIf { it.isNotBlank() }
 91→                        ?.let {
 92→                            ref.add(
 93→                                Reference(
 94→                                    it.removeBackticksAndTrim(),
 95→                                    node.psi.parentDotQualifiedExpression() != null,
 96→                                ),
 97→                            )
 98→                        }
 99→                }
100→            }
101→            BY_KEYWORD -> foundByKeyword = true
102→        }
103→    }
104→
105→    override fun afterVisitChildNodes(
106→        node: ASTNode,
107→        autoCorrect: Boolean,
108→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
109→    ) {
110→        if (node.elementType == FILE) {
111→            val directCalls = ref.filter { !it.inDotQualifiedExpression }.map { it.text }
112→            parentExpressions.forEach { parent ->
113→                imports
114→                    .filterKeys { import ->
115→                        val importPath = import.pathStr.removeBackticksAndTrim()
116→                        importPath.endsWith(".$parent") && directCalls.none { importPath.endsWith(".$it") }
117→                    }.forEach { (importPath, importNode) ->
118→                        emit(importNode.startOffset, "Unused import", true)
119→                        if (autoCorrect) {
120→                            imports.remove(importPath, importNode)
121→                            importNode.removeImportDirective()
122→                        }
123→                    }
124→            }
125→
126→            imports.forEach { (_, node) ->
127→                val importDirective = node.psi as KtImportDirective
128→                val name = importDirective.importPath?.importedName?.asString()?.removeBackticksAndTrim()
129→                val importPath = importDirective.importPath?.pathStr?.removeBackticksAndTrim()!!
130→                if (importDirective.aliasName == null &&
131→                    (packageName.isEmpty() || importPath.startsWith("$packageName.")) &&
132→                    importPath.substring(packageName.length + 1).indexOf('.') == -1
133→                ) {
134→                    emit(node.startOffset, "Unnecessary import", true)
135→                    if (autoCorrect) {
136→                        importDirective.delete()
137→                    }
138→                } else if (name != null && (!ref.map { it.text }.contains(name) || !isAValidImport(importPath)) &&
139→                    !OPERATOR_SET.contains(name) &&
140→                    !name.isComponentN() &&
141→                    !importPath.ignoreProvideDelegate()
142→                ) {
143→                    emit(node.startOffset, "Unused import", true)
144→                    if (autoCorrect) {
145→                        importDirective.delete()
146→                    }
147→                }
148→            }
149→        }
150→    }
151→
152→    private fun String.ignoreProvideDelegate() =
153→        if (endsWith(".provideDelegate")) {
154→            // Ignore provideDelegate if the `by` keyword is found anywhere in the file
155→            foundByKeyword
156→        } else {
157→            false
158→        }
159→
160→    private fun ASTNode.removeImportDirective() {
161→        require(this.elementType == IMPORT_DIRECTIVE)
162→        when {
163→            treeParent.firstChildNode == this -> {
164→                nextSibling { true }
165→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
166→                    ?.let { it.treeParent.removeChild(it) }
167→            }
168→            treeParent.lastChildNode == this -> {
169→                prevSibling { true }
170→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
171→                    ?.let { it.treeParent.removeChild(it) }
172→            }
173→            else -> {
174→                nextLeaf(true)
175→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
176→                    ?.let { it.treeParent.removeChild(it) }
177→            }
178→        }
179→        treeParent.removeChild(this)
180→    }
181→
182→    private fun ASTNode.isExpressionForStaticImportWithExistingParentImport(): Boolean {
183→        if (!containsMethodCall()) {
184→            return false
185→        }
186→
187→        val methodCallExpression = text.substringBeforeLast(
188→            "(",
189→        )
190→
191→        // Only check static imports; identified if they start with a capital letter indicating a
192→        // class name rather than a sub-package
193→        if (methodCallExpression.isNotEmpty() && methodCallExpression[0] !in 'A'..'Z') {
194→            return false
195→        }
196→
197→        imports
198→            .filterKeys { it.pathStr.removeBackticksAndTrim().endsWith(".$methodCallExpression") }
199→            .forEach { import ->
200→                val count = imports.count {
201→                    it.key.pathStr.removeBackticksAndTrim().startsWith(
202→                        import.key.pathStr.removeBackticksAndTrim().substringBefore(methodCallExpression),
203→                    )
204→                }
205→                // Parent import and static import both are present
206→                if (count > 1) {
207→                    return true
208→                }
209→            }
210→        return false
211→    }
212→
213→    private fun ASTNode.containsMethodCall() = text.split(".").last().contains("(")
214→
215→    // Check if the import being checked is present in the filtered import list
216→    private fun isAValidImport(importPath: String) =
217→        imports.any {
218→            it.key.pathStr.removeBackticksAndTrim().contains(importPath)
219→        }
220→
221→    private fun String.isComponentN() = COMPONENT_N_REGEX.matches(this)
222→
223→    private fun PsiElement.parentDotQualifiedExpression(): KtDotQualifiedExpression? {
224→        val callOrThis = (parent as? KtCallExpression)?.takeIf { it.calleeExpression == this } ?: this
225→        return (callOrThis.parent as? KtDotQualifiedExpression)?.takeIf { it.selectorExpression == callOrThis }
226→    }
227→
228→    private fun String.removeBackticksAndTrim() = replace("`", "").trim()
229→
230→    private data class Reference(val text: String, val inDotQualifiedExpression: Boolean)
231→
232→    private companion object {
233→        val COMPONENT_N_REGEX = Regex("^component\\d+$")
234→
235→        val OPERATOR_SET = setOf(
236→            // unary
237→            "unaryPlus", "unaryMinus", "not",
238→            // inc/dec
239→            "inc", "dec",
240→            // arithmetic
241→            "plus", "minus", "times", "div", "rem", "mod", "rangeTo",
242→            // in
243→            "contains",
244→            // indexed access
245→            "get", "set",
246→            // invoke
247→            "invoke",
248→            // augmented assignments
249→            "plusAssign", "minusAssign", "timesAssign", "divAssign", "modAssign",
250→            // (in)equality
251→            "equals",
252→            // comparison
253→            "compareTo",
254→            // iteration (https://github.com/shyiko/ktlint/issues/40)
255→            "iterator",
256→            // by (https://github.com/shyiko/ktlint/issues/54)
257→            "getValue", "setValue",
258→        )
259→    }
260→}
