 31→public class NoUnusedImportsRule : StandardRule("no-unused-imports") {
 32→    private val ref = mutableSetOf(
 33→        Reference("*", false),
 34→    )
 35→    private val parentExpressions = mutableSetOf<String>()
 36→    private val imports = mutableMapOf<ImportPath, ASTNode>()
 37→    private var packageName = ""
 38→    private var rootNode: ASTNode? = null
 39→    private var foundByKeyword = false
