 41→    override fun beforeVisitChildNodes(
 42→        node: ASTNode,
 43→        autoCorrect: Boolean,
 44→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 45→    ) {
 46→        if (node.isRoot()) {
 47→            rootNode = node
 48→        }
 49→        when (node.elementType) {
 50→            PACKAGE_DIRECTIVE -> {
 51→                val packageDirective = node.psi as KtPackageDirective
 52→                packageName = packageDirective.qualifiedName
 53→            }
 54→            IMPORT_DIRECTIVE -> {
 55→                val importPath = (node.psi as KtImportDirective).importPath!!
 56→                if (imports.containsKey(importPath)) {
 57→                    // Emit directly when same import occurs more than once
 58→                    emit(node.startOffset, "Unused import", true)
 59→                    if (autoCorrect) {
 60→                        node.psi.delete()
 61→                    }
 62→                } else {
 63→                    imports[importPath] = node
 64→                }
 65→            }
 66→            DOT_QUALIFIED_EXPRESSION -> {
 67→                if (node.isExpressionForStaticImportWithExistingParentImport()) {
 68→                    parentExpressions.add(node.text.substringBeforeLast("("))
 69→                }
 70→            }
 71→            MARKDOWN_LINK -> {
 72→                node
 73→                    .psi
 74→                    .safeAs<KDocLink>()
 75→                    ?.let { kdocLink ->
 76→                        val linkText = kdocLink.getLinkText().removeBackticksAndTrim()
 77→                        ref.add(Reference(linkText.split('.').first(), false))
 78→                        ref.add(Reference(linkText.split('.').last(), false))
 79→                    }
 80→            }
 81→            REFERENCE_EXPRESSION, OPERATION_REFERENCE -> {
 82→                if (!node.isPartOf(IMPORT_DIRECTIVE)) {
 83→                    val identifier = if (node is CompositeElement) {
 84→                        node.findChildByType(IDENTIFIER)
 85→                    } else {
 86→                        node
 87→                    }
 88→                    identifier
 89→                        ?.let { identifier.text }
 90→                        ?.takeIf { it.isNotBlank() }
 91→                        ?.let {
 92→                            ref.add(
 93→                                Reference(
 94→                                    it.removeBackticksAndTrim(),
 95→                                    node.psi.parentDotQualifiedExpression() != null,
 96→                                ),
 97→                            )
 98→                        }
 99→                }
100→            }
101→            BY_KEYWORD -> foundByKeyword = true
102→        }
103→    }
