105→    override fun afterVisitChildNodes(
106→        node: ASTNode,
107→        autoCorrect: Boolean,
108→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
109→    ) {
110→        if (node.elementType == FILE) {
111→            val directCalls = ref.filter { !it.inDotQualifiedExpression }.map { it.text }
112→            parentExpressions.forEach { parent ->
113→                imports
114→                    .filterKeys { import ->
115→                        val importPath = import.pathStr.removeBackticksAndTrim()
116→                        importPath.endsWith(".$parent") && directCalls.none { importPath.endsWith(".$it") }
117→                    }.forEach { (importPath, importNode) ->
118→                        emit(importNode.startOffset, "Unused import", true)
119→                        if (autoCorrect) {
120→                            imports.remove(importPath, importNode)
121→                            importNode.removeImportDirective()
122→                        }
123→                    }
124→            }
125→
126→            imports.forEach { (_, node) ->
127→                val importDirective = node.psi as KtImportDirective
128→                val name = importDirective.importPath?.importedName?.asString()?.removeBackticksAndTrim()
129→                val importPath = importDirective.importPath?.pathStr?.removeBackticksAndTrim()!!
130→                if (importDirective.aliasName == null &&
131→                    (packageName.isEmpty() || importPath.startsWith("$packageName.")) &&
132→                    importPath.substring(packageName.length + 1).indexOf('.') == -1
133→                ) {
134→                    emit(node.startOffset, "Unnecessary import", true)
135→                    if (autoCorrect) {
136→                        importDirective.delete()
137→                    }
138→                } else if (name != null && (!ref.map { it.text }.contains(name) || !isAValidImport(importPath)) &&
139→                    !OPERATOR_SET.contains(name) &&
140→                    !name.isComponentN() &&
141→                    !importPath.ignoreProvideDelegate()
