162→        when {
163→            treeParent.firstChildNode == this -> {
164→                nextSibling { true }
165→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
166→                    ?.let { it.treeParent.removeChild(it) }
167→            }
168→            treeParent.lastChildNode == this -> {
169→                prevSibling { true }
170→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
171→                    ?.let { it.treeParent.removeChild(it) }
172→            }
173→            else -> {
174→                nextLeaf(true)
175→                    ?.takeIf { it.isWhiteSpaceWithNewline() }
176→                    ?.let { it.treeParent.removeChild(it) }
177→            }
178→        }
179→        treeParent.removeChild(this)
180→    }
