182→    private fun ASTNode.isExpressionForStaticImportWithExistingParentImport(): Boolean {
183→        if (!containsMethodCall()) {
184→            return false
185→        }
186→
187→        val methodCallExpression = text.substringBeforeLast(
188→            "(",
189→        )
190→
191→        // Only check static imports; identified if they start with a capital letter indicating a
192→        // class name rather than a sub-package
193→        if (methodCallExpression.isNotEmpty() && methodCallExpression[0] !in 'A'..'Z') {
194→            return false
195→        }
196→
197→        imports
198→            .filterKeys { it.pathStr.removeBackticksAndTrim().endsWith(".$methodCallExpression") }
199→            .forEach { import ->
200→                val count = imports.count {
201→                    it.key.pathStr.removeBackticksAndTrim().startsWith(
202→                        import.key.pathStr.removeBackticksAndTrim().substringBefore(methodCallExpression),
203→                    )
204→                }
205→                // Parent import and static import both are present
206→                if (count > 1) {
207→                    return true
208→                }
209→            }
210→        return false
211→    }
212→
213→    private fun ASTNode.containsMethodCall() = text.split(".").last().contains("(")
214→
215→    // Check if the import being checked is present in the filtered import list
216→    private fun isAValidImport(importPath: String) =
217→        imports.any {
218→            it.key.pathStr.removeBackticksAndTrim().contains(importPath)
219→        }
220→
221→    private fun String.isComponentN() = COMPONENT_N_REGEX.matches(this)
222→
223→    private fun PsiElement.parentDotQualifiedExpression(): KtDotQualifiedExpression? {
224→        val callOrThis = (parent as? KtCallExpression)?.takeIf { it.calleeExpression == this } ?: this
225→        return (callOrThis.parent as? KtDotQualifiedExpression)?.takeIf { it.selectorExpression == callOrThis }
226→    }
227→
228→    private fun String.removeBackticksAndTrim() = replace("`", "").trim()
229→
230→    private data class Reference(val text: String, val inDotQualifiedExpression: Boolean)
231→
232→    private companion object {
233→        val COMPONENT_N_REGEX = Regex("^component\\d+$")
234→
235→        val OPERATOR_SET = setOf(
236→            // unary
237→            "unaryPlus", "unaryMinus", "not",
238→            // inc/dec
239→            "inc", "dec",
240→            // arithmetic
241→            "plus", "minus", "times", "div", "rem", "mod", "rangeTo",
242→            // in
243→            "contains",
244→            // indexed access
245→            "get", "set",
246→            // invoke
247→            "invoke",
248→            // augmented assignments
249→            "plusAssign", "minusAssign", "timesAssign", "divAssign", "modAssign",
250→            // (in)equality
251→            "equals",
252→            // comparison
253→            "compareTo",
254→            // iteration (https://github.com/shyiko/ktlint/issues/40)
255→            "iterator",
256→            // by (https://github.com/shyiko/ktlint/issues/54)
257→            "getValue", "setValue",
258→        )
259→    }
260→}
