111→    private fun ASTNode.isPartOfRawMultiLineString() =
112→        parent(ElementType.STRING_TEMPLATE, strict = false)
113→            ?.let { it.firstChildNode.text == "\"\"\"" && it.textContains('\n') } == true
114→
115→    public companion object {
116→        public val IGNORE_BACKTICKED_IDENTIFIER_PROPERTY: EditorConfigProperty<Boolean> =
117→            EditorConfigProperty(
118→                type = PropertyType.LowerCasingPropertyType(
119→                    "ktlint_ignore_back_ticked_identifier",
120→                    "Defines whether the backticked identifier (``) should be ignored",
121→                    PropertyType.PropertyValueParser.BOOLEAN_VALUE_PARSER,
122→                    setOf(true.toString(), false.toString()),
123→                ),
124→                defaultValue = false,
125→            )
126→    }
127→}
